class FlaskJWTWrapper:
    """Flask integration for the JWT wrapper."""

    def __init__(self, app: Optional[Flask] = None):
        self.app = app
        self._jwt_wrappers: dict[str, JWTWrapper] = {}
        self._default_wrapper_name: Optional[str] = None

        if app is not None:
            self.init_app(app)

    def init_app(self, app: Flask):
        """Initialize with a Flask app."""
        self.app = app
        app.extensions['jwt_wrapper'] = self

        # Set default config
        app.config.setdefault('JWT_HEADER_NAME', 'Authorization')
        app.config.setdefault('JWT_HEADER_PREFIX', 'Bearer')
        app.config.setdefault('JWT_TOKEN_LOCATION', 'headers')

    def register_wrapper(self, name: str, wrapper: JWTWrapper, default: bool = False):
        """
        Register a named JWT wrapper for different services/contexts.

        Args:
            name: A name for this wrapper (e.g., 'internal', 'public_api').
            wrapper: The JWTWrapper instance.
            default: Whether this should be the default wrapper.
        """
        self._jwt_wrappers[name] = wrapper
        if default or self._default_wrapper_name is None:
            self._default_wrapper_name = name

    def get_wrapper(self, name: Optional[str] = None) -> JWTWrapper:
        """Get a registered JWT wrapper by name."""
        if name is None:
            name = self._default_wrapper_name
        if name is None or name not in self._jwt_wrappers:
            raise JWTError(f"No JWT wrapper registered with name: {name}")
        return self._jwt_wrappers[name]

    def _extract_token(self) -> str:
        """Extract JWT token from the request."""
        header_name = self.app.config['JWT_HEADER_NAME']
        header_prefix = self.app.config['JWT_HEADER_PREFIX']

        auth_header = request.headers.get(header_name)
        if not auth_header:
            raise JWTDecodeError(f"Missing {header_name} header")

        parts = auth_header.split()
        if len(parts) != 2:
            raise JWTDecodeError(f"Invalid {header_name} header format")

        if parts[0] != header_prefix:
            raise JWTDecodeError(
                f"Invalid header prefix. Expected: {header_prefix}, Got: {parts[0]}"
            )

        return parts[1]

    def jwt_required(self, wrapper_name: Optional[str] = None,
                     algorithm: Optional[str] = None,
                     required_claims: Optional[list[str]] = None):
        """
        Decorator to require a valid JWT token for a route.

        Args:
            wrapper_name: Which registered wrapper to use for verification.
            algorithm: Specific algorithm to require (overrides wrapper's allowed list).
            required_claims: List of claim names that must be present in the payload.
        """
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                try:
                    token = self._extract_token()
                    wrapper = self.get_wrapper(wrapper_name)
                    payload = wrapper.decode(token, algorithm=algorithm)

                    # Check required claims
                    if required_claims:
                        for claim in required_claims:
                            if claim not in payload:
                                return jsonify({
                                    'error': 'missing_claim',
                                    'message': f"Token is missing required claim: {claim}"
                                }), 401

                    # Store payload in Flask's g object
                    g.jwt_payload = payload
                    g.jwt_identity = payload.get('sub')

                except JWTExpiredError as e:
                    return jsonify({
                        'error': 'token_expired',
                        'message': str(e)
                    }), 401
                except JWTInvalidSignatureError as e:
                    return jsonify({
                        'error': 'invalid_signature',
                        'message': str(e)
                    }), 401
                except JWTAlgorithmError as e:
                    return jsonify({
                        'error': 'algorithm_error',
                        'message': str(e)
                    }), 401
                except JWTError as e:
                    return jsonify({
                        'error': 'invalid_token',
                        'message': str(e)
                    }), 401

                return f(*args, **kwargs)
            return decorated_function
        return decorator


def create_token_payload(subject: str,
                         expires_in: int = 3600,
                         issuer: Optional[str] = None,
                         audience: Optional[str] = None,
                         additional_claims: Optional[dict] = None) -> dict:
    """
    Helper to create a standard JWT payload with common claims.

    Args:
        subject: The subject (usually user ID).
        expires_in: Token lifetime in seconds (default: 1 hour).
        issuer: Token issuer.
        audience: Token audience.
        additional_claims: Additional claims to include.

    Returns:
        A dictionary with the JWT payload.
    """
    now = time.time()
    payload = {
        'sub': subject,
        'iat': int(now),
        'exp': int(now + expires_in),
    }

    if issuer:
        payload['iss'] = issuer
    if audience:
        payload['aud'] = audience
    if additional_claims:
        # Don't allow overriding standard claims via additional_claims
        protected_claims = {'sub', 'iat', 'exp', 'iss', 'aud'}
        for key, value in additional_claims.items():
            if key not in protected_claims:
                payload[key] = value

    return payload


